data=json.load(sys.stdin)
for folder, emails in data.items():
    if folder.lower() in ['sent','drafts']:
        for e in emails:
            txt=json.dumps(e).lower()
            if any(k in txt for k in ['gluten','dietary','river','katherine','menu']):
                print(json.dumps(e, indent=2))
" 2>&1

# Check what folders exist and search sent
python3 ~/.openclaw/skills/email/email_data.py show --offset 0 --limit 500 2>&1 | python3 -c "
import json,sys
data=json.load(sys.stdin)
if isinstance(data, dict):
    for folder in data:
        emails = data[folder]
        print(f'{folder}: {len(emails)} emails')
        for e in emails:
            txt=json.dumps(e).lower()
            if 'gluten' in txt or 'river' in txt or 'katherine' in txt:
                print('  MATCH:', e.get('email_id'), e.get('subject'))
" 2>&1

